//! Differential test: the Rust CORE must reproduce the Python kernel's distinctions exactly.
//! The oracle is `golden_kernel.tsv`, generated by the Python `reality_kernel` (the reference model).
//! This is semantic preservation, not a reimplementation that happens to look similar.

use reality_core::*;

fn build() -> Core {
    let mut c = Core::new();
    let mut ev = Event::new("gravity", "1.0", "0.5", "developer").unwrap();
    ev.survival = vec![true];
    ev.justification = "gameplay_constraint".into();
    c.apply(&ev, None).unwrap();
    c.record_nonrecovery(
        "relation_R",
        Case { signal_present: false, alternative_cause_matches: false, resolves_under_richer_admissibility: false, resolves_under_richer_observer: false },
        None,
    );
    c.record_nonrecovery(
        "relation_S",
        Case { signal_present: true, alternative_cause_matches: false, resolves_under_richer_admissibility: true, resolves_under_richer_observer: false },
        Some("instrument_validity_A"),
    );
    c.record_nonrecovery(
        "relation_T",
        Case { signal_present: true, alternative_cause_matches: false, resolves_under_richer_admissibility: false, resolves_under_richer_observer: true },
        None,
    );
    c
}

#[test]
fn differential_matches_python_oracle() {
    let c = build();
    let golden = include_str!("../golden_kernel.tsv");
    let mut checked = 0;
    for line in golden.lines().filter(|l| !l.trim().is_empty()) {
        let f: Vec<&str> = line.split('\t').collect();
        assert_eq!(f.len(), 4, "malformed golden line: {:?}", line);
        let (target, exist, diag, res) = (f[0], f[1], f[2], f[3]);
        let q = c.query(target);
        assert_eq!(q.existence.name(), exist, "existence mismatch for {}", target);
        assert_eq!(q.diag_str(), diag, "diagnosis mismatch for {}", target);
        assert_eq!(q.resolution_path, res, "resolution mismatch for {}", target);
        checked += 1;
    }
    assert_eq!(checked, 5, "expected all 5 oracle rows to be checked");
}
